import java.util.*;
public class TwoSumSorted {
    public static int[] twoSum(int[] numbers, int target) {
        int lo = 0, hi = numbers.length - 1;
        while (lo < hi) {
            int sum = numbers[lo] + numbers[hi];
            if (sum == target) return new int[]{lo + 1, hi + 1}; // 1-indexed
            else if (sum < target) lo++;   // need bigger sum
            else hi--;                      // need smaller sum
        }
        return new int[]{}; // guaranteed to have solution
    }
    public static void main(String[] args) {
        System.out.println(Arrays.toString(twoSum(new int[]{2,7,11,15}, 9)));   // [1,2]
        System.out.println(Arrays.toString(twoSum(new int[]{2,3,4}, 6)));       // [1,3]
        System.out.println(Arrays.toString(twoSum(new int[]{-1,0}, -1)));       // [1,2]
        System.out.println("Complexity: O(n) time, O(1) space");
    }
}

