import java.util.Arrays;
public class RemoveDuplicates {
    // Same-direction two pointers:
    // slow: next position to write a unique element
    // fast: scans through all elements
    public static int removeDuplicates(int[] nums) {
        if (nums.length == 0) return 0;
        int slow = 1; // first element is always unique, start slow at 1
        for (int fast = 1; fast < nums.length; fast++) {
            if (nums[fast] != nums[fast - 1]) { // new unique element found
                nums[slow] = nums[fast]; // write to slow position
                slow++;
            }
            // if duplicate: fast advances but slow stays
        }
        return slow; // number of unique elements
    }
    public static void main(String[] args) {
        int[] a = {1,1,2};
        int k = removeDuplicates(a);
        System.out.println(k + " " + Arrays.toString(Arrays.copyOf(a, k))); // 2 [1,2]
        int[] b = {0,0,1,1,1,2,2,3,3,4};
        k = removeDuplicates(b);
        System.out.println(k + " " + Arrays.toString(Arrays.copyOf(b, k))); // 5 [0,1,2,3,4]
        System.out.println("O(n) time, O(1) space — slow/fast same-direction pointers");
    }
}

