public class ContainerWater {
    public static int maxArea(int[] height) {
        int lo = 0, hi = height.length - 1;
        int maxWater = 0;
        while (lo < hi) {
            int water = Math.min(height[lo], height[hi]) * (hi - lo);
            maxWater = Math.max(maxWater, water);
            // Move the shorter side — moving taller can never help
            if (height[lo] < height[hi]) lo++;
            else hi--;
        }
        return maxWater;
    }
    public static void main(String[] args) {
        System.out.println(maxArea(new int[]{1,8,6,2,5,4,8,3,7})); // 49
        System.out.println(maxArea(new int[]{1,1}));                // 1
        System.out.println(maxArea(new int[]{4,3,2,1,4}));          // 16
        System.out.println("O(n) time, O(1) space");
        System.out.println("Key: always move the SHORTER pointer inward");
    }
}

