import java.util.*;
public class ThreeSum {
    public static List<List<Integer>> threeSum(int[] nums) {
        List<List<Integer>> result = new ArrayList<>();
        Arrays.sort(nums); // O(n log n)
        for (int i = 0; i < nums.length - 2; i++) {
            // Skip duplicate values for the fixed element:
            if (i > 0 && nums[i] == nums[i - 1]) continue;
            // Early exit: if smallest possible sum > 0, no triplet exists:
            if (nums[i] > 0) break;
            int lo = i + 1, hi = nums.length - 1;
            while (lo < hi) {
                int sum = nums[i] + nums[lo] + nums[hi];
                if (sum == 0) {
                    result.add(Arrays.asList(nums[i], nums[lo], nums[hi]));
                    // Skip duplicates for lo and hi:
                    while (lo < hi && nums[lo] == nums[lo + 1]) lo++;
                    while (lo < hi && nums[hi] == nums[hi - 1]) hi--;
                    lo++; hi--;
                } else if (sum < 0) lo++;
                else hi--;
            }
        }
        return result;
    }
    public static void main(String[] args) {
        System.out.println(threeSum(new int[]{-1,0,1,2,-1,-4})); // [[-1,-1,2],[-1,0,1]]
        System.out.println(threeSum(new int[]{0,1,1}));           // []
        System.out.println(threeSum(new int[]{0,0,0}));           // [[0,0,0]]
        System.out.println("O(n²) time: O(n log n) sort + O(n) per fixed element × n elements");
    }
}

