import java.util.Arrays;
public class MoveZeroes {
    public static void moveZeroes(int[] nums) {
        int slow = 0; // next position to write a non-zero element
        // Pass 1: move all non-zeros to front (maintaining order)
        for (int fast = 0; fast < nums.length; fast++) {
            if (nums[fast] != 0) {
                nums[slow++] = nums[fast];
            }
        }
        // Pass 2: fill remaining positions with zeros
        while (slow < nums.length) nums[slow++] = 0;
    }
    public static void main(String[] args) {
        int[] a = {0,1,0,3,12}; moveZeroes(a);
        System.out.println(Arrays.toString(a)); // [1,3,12,0,0]
        int[] b = {0}; moveZeroes(b);
        System.out.println(Arrays.toString(b)); // [0]
        int[] c = {1,2,3}; moveZeroes(c);
        System.out.println(Arrays.toString(c)); // [1,2,3]
        System.out.println("O(n) time, O(1) space — two passes");
    }
}

