import java.util.Arrays;
public class SortedSquares {
    public static int[] sortedSquares(int[] nums) {
        int n = nums.length;
        int[] result = new int[n];
        int lo = 0, hi = n - 1;
        int pos = n - 1; // fill result from the back (largest first)
        while (lo <= hi) {
            int lSq = nums[lo] * nums[lo];
            int rSq = nums[hi] * nums[hi];
            if (lSq > rSq) {
                result[pos--] = lSq;
                lo++;
            } else {
                result[pos--] = rSq;
                hi--;
            }
        }
        return result;
    }
    public static void main(String[] args) {
        System.out.println(Arrays.toString(sortedSquares(new int[]{-4,-1,0,3,10})));
        System.out.println(Arrays.toString(sortedSquares(new int[]{-7,-3,2,3,11})));
        System.out.println("O(n) time, O(n) space — result array");
        System.out.println("Key: largest squares always at the ends of sorted array");
    }
}

