import java.util.*;
public class TwoSumIndices {
    public static int[] twoSum(int[] nums, int target) {
        // HashMap: value → index (for looking up complement)
        Map<Integer, Integer> seen = new HashMap<>();
        for (int i = 0; i < nums.length; i++) {
            int complement = target - nums[i];
            if (seen.containsKey(complement)) {
                return new int[]{seen.get(complement), i};
            }
            seen.put(nums[i], i);
        }
        return new int[]{}; // guaranteed to find
    }
    public static void main(String[] args) {
        System.out.println(Arrays.toString(twoSum(new int[]{2,7,11,15}, 9)));  // [0,1]
        System.out.println(Arrays.toString(twoSum(new int[]{3,2,4}, 6)));      // [1,2]
        System.out.println(Arrays.toString(twoSum(new int[]{3,3}, 6)));        // [0,1]
        System.out.println("O(n) time, O(n) space — HashMap complement lookup");
        System.out.println("Key: seen.put AFTER check (allows using same index twice check)");
    }
}

