public class TrappingRainWater {
    public static int trap(int[] height) {
        if (height.length == 0) return 0;
        int lo = 0, hi = height.length - 1;
        int maxLeft = 0, maxRight = 0, totalWater = 0;
        while (lo < hi) {
            if (height[lo] < height[hi]) {
                // Left side is shorter: process from left
                // maxLeft is the actual max height seen so far from left
                if (height[lo] >= maxLeft) {
                    maxLeft = height[lo]; // update max
                } else {
                    totalWater += maxLeft - height[lo]; // trapped water
                }
                lo++;
            } else {
                // Right side is shorter (or equal): process from right
                if (height[hi] >= maxRight) {
                    maxRight = height[hi];
                } else {
                    totalWater += maxRight - height[hi];
                }
                hi--;
            }
        }
        return totalWater;
    }
    public static void main(String[] args) {
        System.out.println(trap(new int[]{0,1,0,2,1,0,1,3,2,1,2,1})); // 6
        System.out.println(trap(new int[]{4,2,0,3,2,5})); // 9
        System.out.println("O(n) time, O(1) space");
        System.out.println("Key insight: process from the shorter side");
        System.out.println("  We know the limiting wall for each side");
    }
}

