public class MinWindowSubstring {
    public static String minWindow(String s, String t) {
        if (s.isEmpty() || t.isEmpty()) return "";
        // Frequency of characters needed:
        int[] need = new int[128];
        for (char c : t.toCharArray()) need[c]++;
        int required = t.length(); // total chars still needed
        int lo = 0, minLen = Integer.MAX_VALUE, minStart = 0;
        int[] window = new int[128];
        for (int hi = 0; hi < s.length(); hi++) {
            // Expand right:
            char c = s.charAt(hi);
            window[c]++;
            if (need[c] > 0 && window[c] <= need[c]) required--; // satisfied one
            // Contract left when all chars covered:
            while (required == 0) {
                if (hi - lo + 1 < minLen) { minLen = hi - lo + 1; minStart = lo; }
                char left = s.charAt(lo);
                window[left]--;
                if (need[left] > 0 && window[left] < need[left]) required++; // lost one
                lo++;
            }
        }
        return minLen == Integer.MAX_VALUE ? "" : s.substring(minStart, minStart + minLen);
    }
    public static void main(String[] args) {
        System.out.println(minWindow("ADOBECODEBANC", "ABC")); // BANC
        System.out.println(minWindow("a", "a"));               // a
        System.out.println(minWindow("a", "aa"));              // (empty)
        System.out.println("O(|s| + |t|) time, O(1) space (fixed 128-char array)");
    }
}

